import{_ as t,o as s,c as a,ai as r}from"./chunks/framework.Bke2s2V8.js";const v=JSON.parse('{"title":"Salutations","description":"","frontmatter":{},"headers":[],"relativePath":"module-1-fondations/salutations.md","filePath":"module-1-fondations/salutations.md","lastUpdated":1773298982000}'),i={name:"module-1-fondations/salutations.md"};function d(n,e,l,o,u,c){return s(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="salutations" tabindex="-1">Salutations <a class="header-anchor" href="#salutations" aria-label="Permalink to “Salutations”">​</a></h1><p><strong>Prérequis :</strong> <a href="./alphabet-prononciation.html">Alphabet et prononciation</a></p><p><strong>Objectif :</strong> savoir dire bonjour, au revoir, merci et comment ca va dans les situations formelles et informelles.</p><p>En allemand, les salutations varient selon l&#39;heure de la journee et le contexte. La distinction formel/informel est importante - les Allemands y attachent de l&#39;importance.</p><h2 id="dire-bonjour" tabindex="-1">Dire bonjour <a class="header-anchor" href="#dire-bonjour" aria-label="Permalink to “Dire bonjour”">​</a></h2><div class="mt-6 grid gap-3"><div class="p-4 rounded-lg border border-gray-200"><div class="flex items-center justify-between"><div class="font-semibold text-gray-900 text-lg">Hallo !</div><span class="text-xs bg-blue-100 text-blue-700 px-2 py-1 rounded-full">informel</span></div><div class="text-gray-600 mt-1">Salut / Bonjour - peut s&#39;utiliser a toute heure</div></div><div class="p-4 rounded-lg border border-gray-200"><div class="flex items-center justify-between"><div class="font-semibold text-gray-900 text-lg">Guten Morgen !</div><span class="text-xs bg-green-100 text-green-700 px-2 py-1 rounded-full">formel / informel</span></div><div class="text-gray-600 mt-1">Bonjour - utilisé le matin (jusqu&#39;a environ 11h)</div></div><div class="p-4 rounded-lg border border-gray-200"><div class="flex items-center justify-between"><div class="font-semibold text-gray-900 text-lg">Guten Tag !</div><span class="text-xs bg-green-100 text-green-700 px-2 py-1 rounded-full">formel / informel</span></div><div class="text-gray-600 mt-1">Bonjour - a partir de midi. La salutation neutre par excellence, passe partout.</div></div><div class="p-4 rounded-lg border border-gray-200"><div class="flex items-center justify-between"><div class="font-semibold text-gray-900 text-lg">Guten Abend !</div><span class="text-xs bg-green-100 text-green-700 px-2 py-1 rounded-full">formel / informel</span></div><div class="text-gray-600 mt-1">Bonsoir - a partir de 18h environ</div></div><div class="p-4 rounded-lg border border-gray-200"><div class="flex items-center justify-between"><div class="font-semibold text-gray-900 text-lg">Gute Nacht !</div><span class="text-xs bg-purple-100 text-purple-700 px-2 py-1 rounded-full">avant de dormir</span></div><div class="text-gray-600 mt-1">Bonne nuit - uniquement avant d&#39;aller se coucher</div></div></div><div class="warning custom-block"><p class="custom-block-title">Gute Nacht n&#39;est pas Bonsoir</p><p><em>Gute Nacht</em> se dit uniquement quand on va dormir - pas en sortant d&#39;un dîner ou d&#39;une soirée. Dans ce cas, on utilisé <em>Tschüss</em> ou <em>Auf Wiedersehen</em>.</p></div><h2 id="dire-au-revoir" tabindex="-1">Dire au revoir <a class="header-anchor" href="#dire-au-revoir" aria-label="Permalink to “Dire au revoir”">​</a></h2><div class="mt-4 grid gap-3"><div class="p-4 rounded-lg border border-gray-200"><div class="flex items-center justify-between"><div class="font-semibold text-gray-900 text-lg">Tschüss !</div><span class="text-xs bg-blue-100 text-blue-700 px-2 py-1 rounded-full">informel</span></div><div class="text-gray-600 mt-1">Au revoir / Salut - la façon la plus courante de dire au revoir</div></div><div class="p-4 rounded-lg border border-gray-200"><div class="flex items-center justify-between"><div class="font-semibold text-gray-900 text-lg">Auf Wiedersehen !</div><span class="text-xs bg-orange-100 text-orange-700 px-2 py-1 rounded-full">formel</span></div><div class="text-gray-600 mt-1">Au revoir - litteralement &quot;a la prochaine fois qu&#39;on se verra&quot;</div></div><div class="p-4 rounded-lg border border-gray-200"><div class="flex items-center justify-between"><div class="font-semibold text-gray-900 text-lg">Bis bald !</div><span class="text-xs bg-blue-100 text-blue-700 px-2 py-1 rounded-full">informel</span></div><div class="text-gray-600 mt-1">A bientot</div></div><div class="p-4 rounded-lg border border-gray-200"><div class="flex items-center justify-between"><div class="font-semibold text-gray-900 text-lg">Bis morgen !</div><span class="text-xs bg-blue-100 text-blue-700 px-2 py-1 rounded-full">informel</span></div><div class="text-gray-600 mt-1">A demain - *bis* + un complément de temps fonctionne toujours : *bis Montag* (a lundi)</div></div></div><h2 id="comment-ca-va" tabindex="-1">Comment ca va ? <a class="header-anchor" href="#comment-ca-va" aria-label="Permalink to “Comment ca va ?”">​</a></h2><div class="mt-4 grid gap-3"><div class="p-4 rounded-lg border border-green-100 bg-green-50"><div class="font-semibold text-gray-900">Wie geht es Ihnen ?</div><div class="text-sm text-gray-500 mt-1">Comment allez-vous ? - <strong>formel</strong>, avec vouvoiement (*Sie*)</div></div><div class="p-4 rounded-lg border border-green-100 bg-green-50"><div class="font-semibold text-gray-900">Wie geht es dir ? / Wie geht&#39;s ?</div><div class="text-sm text-gray-500 mt-1">Comment ca va ? - <strong>informel</strong>, avec tutoiement (*du*). *Wie geht&#39;s* est la forme raccourcie très courante.</div></div></div><p><strong>Reponses possibles :</strong></p><ul><li><em>Danke, gut.</em> - Merci, bien.</li><li><em>Sehr gut !</em> - Très bien !</li><li><em>Es geht.</em> - Ca va. (moyen)</li><li><em>Nicht so gut.</em> - Pas très bien.</li></ul><h2 id="remerciements-et-politesse-de-base" tabindex="-1">Remerciements et politesse de base <a class="header-anchor" href="#remerciements-et-politesse-de-base" aria-label="Permalink to “Remerciements et politesse de base”">​</a></h2><table tabindex="0"><thead><tr><th>Allemand</th><th>Français</th></tr></thead><tbody><tr><td>Danke !</td><td>Merci !</td></tr><tr><td>Danke schön ! / Danke sehr !</td><td>Merci beaucoup !</td></tr><tr><td>Vielen Dank !</td><td>Merci beaucoup ! (plus formel)</td></tr><tr><td>Bitte !</td><td>S&#39;il vous plait / De rien</td></tr><tr><td>Gern geschehen !</td><td>Avec plaisir / De rien</td></tr><tr><td>Entschuldigung !</td><td>Excusez-moi ! / Pardon !</td></tr><tr><td>Es tut mir leid.</td><td>Je suis desole(e).</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Bitte - un mot, deux sens</p><p><em>Bitte</em> signifie &quot;s&#39;il vous plait&quot; quand on demande quelque chose, et &quot;de rien&quot; quand on répond à un merci. C&#39;est le même mot dans les deux cas - apprends-le une bonne fois pour toutes.</p></div>',16)])])}const p=t(i,[["render",d]]);export{v as __pageData,p as default};
